using System;
using System.Data.SqlClient;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class ReportFunction
{
    [FunctionName("Report")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("AzureSQLConnectionString");
        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("Connection string not found.");
        }

        string query = "SELECT * FROM Reports WHERE 1=1";

        string name = req.Query["name"];
        string category = req.Query["category"];

        if (!string.IsNullOrEmpty(name))
        {
            query += $" AND Name LIKE '%{name}%'";
        }
        if (!string.IsNullOrEmpty(category))
        {
            query += $" AND Category LIKE '%{category}%'";
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                await connection.OpenAsync();
                SqlCommand command = new SqlCommand(query, connection);
                SqlDataReader reader = await command.ExecuteReaderAsync();

                using (var writer = new StringWriter())
                {
                    while (await reader.ReadAsync())
                    {
                        writer.WriteLine(reader["Id"] + ", " + reader["Name"] + ", " + reader["Category"]);
                    }

                    return new OkObjectResult(writer.ToString());
                }
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing SQL query.");
                return new StatusCodeResult(500);
            }
        }
    }
}